import{_ as a,o as d,c as e,a0 as r}from"./chunks/framework.RL10UjUE.js";const o="/bookmark-manager-pe/assets/ai-assistant.OnU7pOvq.png",b=JSON.parse('{"title":"AI アシスタント（Zed AI 連携）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-assistant.md","filePath":"guide/ai-assistant.md"}'),i={name:"guide/ai-assistant.md"};function l(s,t,h,n,c,p){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-アシスタント-zed-ai-連携" tabindex="-1">AI アシスタント（Zed AI 連携） <a class="header-anchor" href="#ai-アシスタント-zed-ai-連携" aria-label="Permalink to &quot;AI アシスタント（Zed AI 連携）&quot;">​</a></h1><p>本ツールはローカル HTTP API サーバを起動し、Zed エディタの AI 機能と連携してブックマークの管理を支援します。</p><h2 id="事前準備" tabindex="-1">事前準備 <a class="header-anchor" href="#事前準備" aria-label="Permalink to &quot;事前準備&quot;">​</a></h2><ol><li><strong>Zed エディタ</strong> がインストールされていること</li><li>Zed の AI 機能が有効化されていること（設定 → AI）</li></ol><h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><h3 id="_1-api-サーバを起動" tabindex="-1">1. API サーバを起動 <a class="header-anchor" href="#_1-api-サーバを起動" aria-label="Permalink to &quot;1. API サーバを起動&quot;">​</a></h3><p>アプリを起動すると、自動的にローカル HTTP サーバが <code>http://localhost:9876</code> で起動します。</p><h3 id="_2-ai-アシスタントパネルを開く" tabindex="-1">2. AI アシスタントパネルを開く <a class="header-anchor" href="#_2-ai-アシスタントパネルを開く" aria-label="Permalink to &quot;2. AI アシスタントパネルを開く&quot;">​</a></h3><p>ヘッダーの <strong>AI</strong> ボタンをクリックすると、AI アシスタントパネルが表示されます。</p><p><img src="'+o+'" alt="AIアシスタントパネル"></p><h3 id="_3-プロンプトをコピー" tabindex="-1">3. プロンプトをコピー <a class="header-anchor" href="#_3-プロンプトをコピー" aria-label="Permalink to &quot;3. プロンプトをコピー&quot;">​</a></h3><p>パネル内のプロンプトテンプレート（Copy ボタン）をクリックして、Zed に貼り付けられる形式でコピーします。</p><p>以下のテンプレートが用意されています。</p><table tabindex="0"><thead><tr><th>テンプレート</th><th>用途</th></tr></thead><tbody><tr><td>タグ付け</td><td>未分類ブックマークに AI がタグを提案</td></tr><tr><td>タイトル整形</td><td>抽出された URL タイトルをクリーンアップ</td></tr><tr><td>AI マージ</td><td>重複ブックマークのマージ判断</td></tr><tr><td>分析</td><td>ブックマークコレクションの分析レポート</td></tr></tbody></table><h3 id="_4-zed-で実行" tabindex="-1">4. Zed で実行 <a class="header-anchor" href="#_4-zed-で実行" aria-label="Permalink to &quot;4. Zed で実行&quot;">​</a></h3><ol><li>Zed を開き、AI チャットを起動（<code>Cmd + I</code>）</li><li>コピーしたプロンプトを貼り付け</li><li>AI が API を呼び出し、結果を JSON で返します</li><li>パネル内の <strong>適用</strong> ボタンで結果をブックマークに反映</li></ol><h3 id="api-エンドポイント" tabindex="-1">API エンドポイント <a class="header-anchor" href="#api-エンドポイント" aria-label="Permalink to &quot;API エンドポイント&quot;">​</a></h3><p>Zed AI からアクセス可能なエンドポイント:</p><table tabindex="0"><thead><tr><th>エンドポイント</th><th>メソッド</th><th>説明</th></tr></thead><tbody><tr><td><code>/api/bookmarks/untagged</code></td><td>GET</td><td>未分類ブックマーク一覧</td></tr><tr><td><code>/api/bookmarks/:id</code></td><td>GET</td><td>単一ブックマークの詳細</td></tr><tr><td><code>/api/bookmarks/:id</code></td><td>PATCH</td><td>ブックマークの更新（タグ・タイトル等）</td></tr><tr><td><code>/api/tags</code></td><td>GET</td><td>全タグ一覧</td></tr><tr><td><code>/api/duplicates</code></td><td>GET</td><td>重複グループ一覧</td></tr><tr><td><code>/api/health</code></td><td>GET</td><td>ヘルスチェック</td></tr></tbody></table>',19)])])}const A=a(i,[["render",l]]);export{b as __pageData,A as default};
